import struct
from flask import Flask, request, jsonify

app = Flask(name)

@app.route('/float_to_bytes', methods=['POST'])
def float_to_bytes():
f = request.json['float']
b = struct.pack('f', f)
return jsonify({'bytes': [x for x in b]})

@app.route('/bytes_to_float', methods=['POST'])
def bytes_to_float():
b = bytes(request.json['bytes'])
f = struct.unpack('f', b)[0]
return jsonify({'float': f})

if name == 'main':
app.run()

